package test.rice.parse;

import main.rice.node.*;
import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Agent tests for ConfigFileParser covering edge cases.
 */
class AgentConfigFileParserTest {

    private ConfigFileParser parser;

    @BeforeEach
    void setUp() {
        parser = new ConfigFileParser();
    }

    // ==================== VALID PARSING TESTS ====================

    @Test
    void testParseSimpleInt() throws InvalidConfigException {
        String json = """
            {
                "fname": "foo",
                "types": ["int"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1~5"],
                "num random": 10
            }
            """;
        ConfigFile config = parser.parse(json);
        assertEquals("foo", config.getFuncName());
        assertEquals(10, config.getNumRand());
        assertEquals(1, config.getNodes().size());
        assertTrue(config.getNodes().get(0) instanceof PyIntNode);

        PyIntNode node = (PyIntNode) config.getNodes().get(0);
        assertEquals(Arrays.asList(1, 2, 3), node.getExDomain());
        assertEquals(Arrays.asList(1, 2, 3, 4, 5), node.getRanDomain());
    }

    @Test
    void testParseSimpleBool() throws InvalidConfigException {
        String json = """
            {
                "fname": "test",
                "types": ["bool"],
                "exhaustive domain": ["0~1"],
                "random domain": ["0~1"],
                "num random": 5
            }
            """;
        ConfigFile config = parser.parse(json);
        assertEquals(1, config.getNodes().size());
        assertTrue(config.getNodes().get(0) instanceof PyBoolNode);
        assertEquals(Arrays.asList(0, 1), config.getNodes().get(0).getExDomain());
    }

    @Test
    void testParseSimpleFloat() throws InvalidConfigException {
        String json = """
            {
                "fname": "test",
                "types": ["float"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1~5"],
                "num random": 0
            }
            """;
        ConfigFile config = parser.parse(json);
        assertEquals(1, config.getNodes().size());
        assertTrue(config.getNodes().get(0) instanceof PyFloatNode);
    }

    @Test
    void testParseMultipleArgs() throws InvalidConfigException {
        String json = """
            {
                "fname": "multi",
                "types": ["int", "bool"],
                "exhaustive domain": ["1~3", "0~1"],
                "random domain": ["1~5", "0~1"],
                "num random": 100
            }
            """;
        ConfigFile config = parser.parse(json);
        assertEquals("multi", config.getFuncName());
        assertEquals(100, config.getNumRand());
        assertEquals(2, config.getNodes().size());
        assertTrue(config.getNodes().get(0) instanceof PyIntNode);
        assertTrue(config.getNodes().get(1) instanceof PyBoolNode);
    }

    @Test
    void testParseListOfInt() throws InvalidConfigException {
        String json = """
            {
                "fname": "listFunc",
                "types": ["list(int)"],
                "exhaustive domain": ["0~2;1~3"],
                "random domain": ["0~3;1~5"],
                "num random": 5
            }
            """;
        ConfigFile config = parser.parse(json);
        assertEquals(1, config.getNodes().size());
        APyNode<?> node = config.getNodes().get(0);
        assertTrue(node instanceof PyListNode);
        assertEquals(Arrays.asList(0, 1, 2), node.getExDomain());
        assertTrue(node.getLeftChild() instanceof PyIntNode);
        assertEquals(Arrays.asList(1, 2, 3), node.getLeftChild().getExDomain());
    }

    @Test
    void testParseSetOfBool() throws InvalidConfigException {
        String json = """
            {
                "fname": "setFunc",
                "types": ["set(bool)"],
                "exhaustive domain": ["0~2;0~1"],
                "random domain": ["0~2;0~1"],
                "num random": 3
            }
            """;
        ConfigFile config = parser.parse(json);
        assertTrue(config.getNodes().get(0) instanceof PySetNode);
    }

    @Test
    void testParseTupleOfInt() throws InvalidConfigException {
        String json = """
            {
                "fname": "tupleFunc",
                "types": ["tuple(int)"],
                "exhaustive domain": ["0~2;1~3"],
                "random domain": ["0~3;1~5"],
                "num random": 2
            }
            """;
        ConfigFile config = parser.parse(json);
        assertTrue(config.getNodes().get(0) instanceof PyTupleNode);
    }

    @Test
    void testParseDictOfIntBool() throws InvalidConfigException {
        String json = """
            {
                "fname": "dictFunc",
                "types": ["dict(int:bool)"],
                "exhaustive domain": ["0~2;1~3;0~1"],
                "random domain": ["0~3;1~5;0~1"],
                "num random": 4
            }
            """;
        ConfigFile config = parser.parse(json);
        APyNode<?> node = config.getNodes().get(0);
        assertTrue(node instanceof PyDictNode);
        assertTrue(node.getLeftChild() instanceof PyIntNode);
        assertTrue(node.getRightChild() instanceof PyBoolNode);
    }

    @Test
    void testParseNestedListOfList() throws InvalidConfigException {
        String json = """
            {
                "fname": "nestedFunc",
                "types": ["list(list(int))"],
                "exhaustive domain": ["0~1;0~1;1~2"],
                "random domain": ["0~2;0~2;1~3"],
                "num random": 3
            }
            """;
        ConfigFile config = parser.parse(json);
        APyNode<?> node = config.getNodes().get(0);
        assertTrue(node instanceof PyListNode);
        assertTrue(node.getLeftChild() instanceof PyListNode);
        assertTrue(node.getLeftChild().getLeftChild() instanceof PyIntNode);
    }

    @Test
    void testParseExplicitList() throws InvalidConfigException {
        String json = """
            {
                "fname": "test",
                "types": ["int"],
                "exhaustive domain": ["[1,3,5]"],
                "random domain": ["[2,4,6]"],
                "num random": 0
            }
            """;
        ConfigFile config = parser.parse(json);
        assertEquals(Arrays.asList(1, 3, 5), config.getNodes().get(0).getExDomain());
        assertEquals(Arrays.asList(2, 4, 6), config.getNodes().get(0).getRanDomain());
    }

    @Test
    void testParseSingleExplicitValue() throws InvalidConfigException {
        String json = """
            {
                "fname": "test",
                "types": ["int"],
                "exhaustive domain": ["[1]"],
                "random domain": ["[1]"],
                "num random": 0
            }
            """;
        ConfigFile config = parser.parse(json);
        assertEquals(Arrays.asList(1), config.getNodes().get(0).getExDomain());
    }

    @Test
    void testNumRandZero() throws InvalidConfigException {
        String json = """
            {
                "fname": "test",
                "types": ["int"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1~5"],
                "num random": 0
            }
            """;
        ConfigFile config = parser.parse(json);
        assertEquals(0, config.getNumRand());
    }

    // ==================== ERROR HANDLING TESTS ====================

    @Test
    void testEmptyString() {
        assertThrows(InvalidConfigException.class, () -> parser.parse(""));
    }

    @Test
    void testEmptyObject() {
        assertThrows(InvalidConfigException.class, () -> parser.parse("{}"));
    }

    @Test
    void testInvalidTypeUnknown() {
        String json = """
            {
                "fname": "test",
                "types": ["char"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1~5"],
                "num random": 10
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    @Test
    void testMismatchedArraySizes() {
        String json = """
            {
                "fname": "test",
                "types": ["int", "bool"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1~5"],
                "num random": 10
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    @Test
    void testInvalidRangeLowerGreaterThanUpper() {
        String json = """
            {
                "fname": "test",
                "types": ["int"],
                "exhaustive domain": ["5~1"],
                "random domain": ["1~5"],
                "num random": 10
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    @Test
    void testSpuriousSpaceRanDomain() {
        String json = """
            {
                "fname": "testFunc",
                "types": ["int"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1 ~5"],
                "num random": 10
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    @Test
    void testSpuriousCloseParen() {
        String json = """
            {
                "fname": "test",
                "types": ["int)"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1~5"],
                "num random": 10
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    @Test
    void testNumRandFloat() {
        String json = """
            {
                "fname": "test",
                "types": ["int"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1~5"],
                "num random": 10.5
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    @Test
    void testDomainWrongPartCount() {
        String json = """
            {
                "fname": "test",
                "types": ["int"],
                "exhaustive domain": ["1~3;1~2"],
                "random domain": ["1~5"],
                "num random": 10
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    @Test
    void testDictMissingColon() {
        String json = """
            {
                "fname": "test",
                "types": ["dict(int)"],
                "exhaustive domain": ["0~1;1~3"],
                "random domain": ["0~1;1~3"],
                "num random": 10
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    // ==================== ConfigFile TESTS ====================

    @Test
    void testGetNumRand() {
        PyIntNode node = new PyIntNode();
        node.setExDomain(Arrays.asList(1, 2, 3));
        node.setRanDomain(Arrays.asList(1, 2, 3));
        ConfigFile config = new ConfigFile("test", Arrays.asList(node), 42);
        assertEquals(42, config.getNumRand());
    }

    @Test
    void testGetNodes() {
        PyIntNode intNode = new PyIntNode();
        intNode.setExDomain(Arrays.asList(1));
        intNode.setRanDomain(Arrays.asList(1));
        PyBoolNode boolNode = new PyBoolNode();
        boolNode.setExDomain(Arrays.asList(0, 1));
        boolNode.setRanDomain(Arrays.asList(0, 1));
        List<APyNode<?>> nodes = Arrays.asList(intNode, boolNode);
        ConfigFile config = new ConfigFile("test", nodes, 10);
        assertEquals(nodes, config.getNodes());
        assertEquals(2, config.getNodes().size());
    }

    @Test
    void testEmptyNodesList() {
        ConfigFile config = new ConfigFile("empty", new ArrayList<>(), 0);
        assertEquals("empty", config.getFuncName());
        assertEquals(0, config.getNumRand());
        assertTrue(config.getNodes().isEmpty());
    }

    // ==================== MORE EDGE CASES ====================

    @Test
    void testNegativeRange() throws InvalidConfigException {
        String json = """
            {
                "fname": "test",
                "types": ["int"],
                "exhaustive domain": ["-3~3"],
                "random domain": ["-5~5"],
                "num random": 0
            }
            """;
        ConfigFile config = parser.parse(json);
        assertEquals(Arrays.asList(-3, -2, -1, 0, 1, 2, 3),
                config.getNodes().get(0).getExDomain());
    }

    @Test
    void testEqualRangeBounds() throws InvalidConfigException {
        String json = """
            {
                "fname": "test",
                "types": ["int"],
                "exhaustive domain": ["3~3"],
                "random domain": ["5~5"],
                "num random": 0
            }
            """;
        ConfigFile config = parser.parse(json);
        assertEquals(Arrays.asList(3), config.getNodes().get(0).getExDomain());
    }

    @Test
    void testParseStr() throws InvalidConfigException {
        String json = """
            {
                "fname": "test",
                "types": ["str"],
                "exhaustive domain": ["0~3;abc"],
                "random domain": ["0~5;abcdef"],
                "num random": 5
            }
            """;
        ConfigFile config = parser.parse(json);
        assertTrue(config.getNodes().get(0) instanceof PyStringNode);
        assertEquals(Arrays.asList(0, 1, 2, 3), config.getNodes().get(0).getExDomain());
    }

    @Test
    void testParseDictNestedKey() throws InvalidConfigException {
        String json = """
            {
                "fname": "test",
                "types": ["dict(list(int):bool)"],
                "exhaustive domain": ["0~1;0~1;1~2;0~1"],
                "random domain": ["0~1;0~1;1~2;0~1"],
                "num random": 0
            }
            """;
        ConfigFile config = parser.parse(json);
        APyNode<?> node = config.getNodes().get(0);
        assertTrue(node instanceof PyDictNode);
        assertTrue(node.getLeftChild() instanceof PyListNode);
        assertTrue(node.getLeftChild().getLeftChild() instanceof PyIntNode);
        assertTrue(node.getRightChild() instanceof PyBoolNode);
    }

    @Test
    void testListUnmatchedParen() {
        String json = """
            {
                "fname": "test",
                "types": ["list(int"],
                "exhaustive domain": ["0~2;1~3"],
                "random domain": ["0~3;1~5"],
                "num random": 10
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    @Test
    void testExtraParenInType() {
        String json = """
            {
                "fname": "test",
                "types": ["list((int))"],
                "exhaustive domain": ["0~2;1~3"],
                "random domain": ["0~3;1~5"],
                "num random": 10
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    @Test
    void testNumRandBooleanValue() {
        String json = """
            {
                "fname": "test",
                "types": ["int"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1~5"],
                "num random": true
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    // ==================== PAREN SEPARATOR TESTS ====================

    @Test
    void testParseListOfIntParenSeparator() throws InvalidConfigException {
        String json = """
            {
                "fname": "listFunc",
                "types": ["list(int)"],
                "exhaustive domain": ["0~2(1~3"],
                "random domain": ["0~3(1~5"],
                "num random": 5
            }
            """;
        ConfigFile config = parser.parse(json);
        assertEquals(1, config.getNodes().size());
        APyNode<?> node = config.getNodes().get(0);
        assertTrue(node instanceof PyListNode);
        assertEquals(Arrays.asList(0, 1, 2), node.getExDomain());
        assertTrue(node.getLeftChild() instanceof PyIntNode);
        assertEquals(Arrays.asList(1, 2, 3), node.getLeftChild().getExDomain());
    }

    @Test
    void testParseNestedListParenSeparator() throws InvalidConfigException {
        String json = """
            {
                "fname": "test",
                "types": ["list(list(int))"],
                "exhaustive domain": ["0~1(0~1(1~2"],
                "random domain": ["0~2(0~2(1~3"],
                "num random": 3
            }
            """;
        ConfigFile config = parser.parse(json);
        APyNode<?> node = config.getNodes().get(0);
        assertTrue(node instanceof PyListNode);
        assertTrue(node.getLeftChild() instanceof PyListNode);
        assertTrue(node.getLeftChild().getLeftChild() instanceof PyIntNode);
    }

    @Test
    void testParseDictParenSeparator() throws InvalidConfigException {
        String json = """
            {
                "fname": "test",
                "types": ["dict(int:bool)"],
                "exhaustive domain": ["0~2(1~3(0~1"],
                "random domain": ["0~3(1~5(0~1"],
                "num random": 4
            }
            """;
        ConfigFile config = parser.parse(json);
        APyNode<?> node = config.getNodes().get(0);
        assertTrue(node instanceof PyDictNode);
        assertTrue(node.getLeftChild() instanceof PyIntNode);
        assertTrue(node.getRightChild() instanceof PyBoolNode);
    }
}

package main.rice;

import main.rice.basegen.BaseSetGenerator;
import main.rice.concisegen.ConciseSetGenerator;
import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import main.rice.test.Tester;

import java.io.*;
import java.nio.file.*;
import java.util.*;

/**
 * The main entry point that ties together config file parsing, test generation,
 * test execution, and concise set selection.
 */
public class Main {

    /**
     * Generates a concise set of test cases that catches all known buggy implementations.
     *
     * @param args [configPath, solutionPath, implDirPath]
     * @return a concise set of test cases
     * @throws IOException              if files cannot be read
     * @throws InvalidConfigException   if the config file is malformed
     * @throws InterruptedException     if test execution is interrupted
     */
    public static Set<TestCase> generateTests(String[] args)
            throws IOException, InvalidConfigException, InterruptedException {
        // Read the config file
        String configContents = Files.readString(Path.of(args[0]));
        String solutionPath = args[1];
        String implDirPath = args[2];

        // Parse the config file
        ConfigFileParser parser = new ConfigFileParser();
        ConfigFile config = parser.parse(configContents);

        // Generate the base test set
        BaseSetGenerator baseGen = new BaseSetGenerator(config.getNodes(), config.getNumRand());
        List<TestCase> baseSet = baseGen.genBaseSet();

        // Run tests on all implementations
        Tester tester = new Tester(config.getFuncName(), solutionPath, implDirPath, baseSet);
        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        // Find the concise (approximately minimal) set
        return ConciseSetGenerator.setCover(results);
    }

    /**
     * Main entry point.
     */
    public static void main(String[] args) {
        try {
            Set<TestCase> conciseSet = generateTests(args);
            System.out.println(conciseSet);
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

package main.rice.parse;

import main.rice.node.APyNode;
import java.util.List;

/**
 * A simple data class representing a parsed configuration file. Stores the function
 * name, the list of nodes (one per parameter), and the number of random tests to
 * generate.
 */
public class ConfigFile {

    private final String funcName;
    private final List<APyNode<?>> nodes;
    private final int numRand;

    /**
     * Constructor for a ConfigFile; initializes all fields.
     *
     * @param funcName the name of the function under test
     * @param nodes    the list of APyNodes for test generation
     * @param numRand  the number of random test cases to generate
     */
    public ConfigFile(String funcName, List<APyNode<?>> nodes, int numRand) {
        this.funcName = funcName;
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Returns the function name.
     *
     * @return the function name
     */
    public String getFuncName() {
        return this.funcName;
    }

    /**
     * Returns the list of nodes.
     *
     * @return the list of APyNodes
     */
    public List<APyNode<?>> getNodes() {
        return this.nodes;
    }

    /**
     * Returns the number of random test cases.
     *
     * @return the number of random test cases
     */
    public int getNumRand() {
        return this.numRand;
    }
}

package main.rice.parse;

import main.rice.node.*;
import org.json.*;
import java.util.*;

/**
 * Parses a JSON configuration file into a ConfigFile object containing the function name,
 * a list of APyNodes with their domains set, and the number of random tests.
 */
public class ConfigFileParser {

    /**
     * Parses the input JSON string into a ConfigFile object.
     *
     * @param contents the JSON string to parse
     * @return a ConfigFile containing the parsed configuration
     * @throws InvalidConfigException if the configuration is malformed
     */
    public ConfigFile parse(String contents) throws InvalidConfigException {
        // Parse JSON
        JSONObject json;
        try {
            json = new JSONObject(contents);
        } catch (JSONException e) {
            throw new InvalidConfigException("Not valid JSON: " + e.getMessage());
        }

        // Check required fields exist
        if (!json.has("fname") || !json.has("types")
                || !json.has("exhaustive domain") || !json.has("random domain")
                || !json.has("num random")) {
            throw new InvalidConfigException("Missing required field");
        }

        // Extract fname (must be a String)
        Object fnameObj = json.get("fname");
        if (!(fnameObj instanceof String)) {
            throw new InvalidConfigException("fname must be a string");
        }
        String fname = (String) fnameObj;

        // Extract types (must be array of strings)
        List<String> types = extractStringArray(json, "types");

        // Extract domains (must be arrays of strings)
        List<String> exDomains = extractStringArray(json, "exhaustive domain");
        List<String> ranDomains = extractStringArray(json, "random domain");

        // Extract numRand (must be a non-negative integer)
        Object numRandObj = json.get("num random");
        if (!(numRandObj instanceof Integer)) {
            throw new InvalidConfigException("num random must be an integer");
        }
        int numRand = (Integer) numRandObj;
        if (numRand < 0) {
            throw new InvalidConfigException("num random must be non-negative");
        }

        // Validate array sizes match
        if (types.size() != exDomains.size() || types.size() != ranDomains.size()) {
            throw new InvalidConfigException("Array sizes don't match type count");
        }

        // Check for spurious characters in domain strings
        for (String domain : exDomains) {
            checkDomainChars(domain);
        }
        for (String domain : ranDomains) {
            checkDomainChars(domain);
        }

        // Parse types and set domains on nodes
        List<APyNode<?>> nodes = new ArrayList<>();
        for (int i = 0; i < types.size(); i++) {
            String[] exParts = splitDomainParts(exDomains.get(i));
            String[] ranParts = splitDomainParts(ranDomains.get(i));
            int[] exIdx = {0};
            int[] ranIdx = {0};
            APyNode<?> node = buildNode(types.get(i), exParts, ranParts, exIdx, ranIdx);
            if (exIdx[0] != exParts.length || ranIdx[0] != ranParts.length) {
                throw new InvalidConfigException("Domain parts don't match type structure");
            }
            nodes.add(node);
        }

        return new ConfigFile(fname, nodes, numRand);
    }

    /**
     * Extracts a JSON array of strings from the given key.
     */
    private List<String> extractStringArray(JSONObject json, String key)
            throws InvalidConfigException {
        Object obj = json.get(key);
        if (!(obj instanceof JSONArray)) {
            throw new InvalidConfigException(key + " must be an array");
        }
        JSONArray arr = (JSONArray) obj;
        List<String> result = new ArrayList<>();
        for (int i = 0; i < arr.length(); i++) {
            Object elem = arr.get(i);
            if (!(elem instanceof String)) {
                throw new InvalidConfigException(key + " must contain only strings");
            }
            result.add((String) elem);
        }
        return result;
    }

    /**
     * Checks a domain string for spurious characters (close-parens or spaces).
     * Open-parens are allowed as domain part separators.
     */
    private void checkDomainChars(String domain) throws InvalidConfigException {
        if (domain.contains(")") || domain.contains(" ")) {
            throw new InvalidConfigException("Spurious character in domain: " + domain);
        }
    }

    /**
     * Splits a domain string into parts using ( or ; as separator.
     * If the domain contains (, splits on (. Otherwise if it contains ;, splits on ;.
     * Otherwise returns the whole string as a single part.
     * Throws if any resulting part is empty (indicating double separator).
     */
    private String[] splitDomainParts(String domain) throws InvalidConfigException {
        String[] parts;
        if (domain.contains("(")) {
            parts = domain.split("\\(", -1);
        } else if (domain.contains(";")) {
            parts = domain.split(";", -1);
        } else {
            parts = new String[]{domain};
        }
        for (String part : parts) {
            if (part.isEmpty()) {
                throw new InvalidConfigException("Spurious character in domain: " + domain);
            }
        }
        return parts;
    }

    /**
     * Recursively builds a node tree from the type string and assigns domains
     * from the provided domain parts arrays.
     */
    @SuppressWarnings("unchecked")
    private APyNode<?> buildNode(String typeStr, String[] exParts, String[] ranParts,
                                  int[] exIdx, int[] ranIdx) throws InvalidConfigException {
        // Check for spaces in type string
        if (typeStr.contains(" ")) {
            throw new InvalidConfigException("Invalid type (contains space): " + typeStr);
        }

        if (typeStr.equals("int")) {
            PyIntNode node = new PyIntNode();
            node.setExDomain(parseDomain(exParts, exIdx));
            node.setRanDomain(parseDomain(ranParts, ranIdx));
            return node;
        } else if (typeStr.equals("bool")) {
            PyBoolNode node = new PyBoolNode();
            node.setExDomain(parseDomain(exParts, exIdx));
            node.setRanDomain(parseDomain(ranParts, ranIdx));
            return node;
        } else if (typeStr.equals("float")) {
            PyFloatNode node = new PyFloatNode();
            node.setExDomain(parseDomain(exParts, exIdx));
            node.setRanDomain(parseDomain(ranParts, ranIdx));
            return node;
        } else if (typeStr.equals("str")) {
            List<Number> exLens = parseDomain(exParts, exIdx);
            String exCharDomain = consumePart(exParts, exIdx);
            List<Number> ranLens = parseDomain(ranParts, ranIdx);
            consumePart(ranParts, ranIdx);
            PyStringNode node = new PyStringNode(exCharDomain);
            node.setExDomain(exLens);
            node.setRanDomain(ranLens);
            return node;
        } else if (typeStr.startsWith("list(") && typeStr.endsWith(")")) {
            String innerType = typeStr.substring(5, typeStr.length() - 1);
            List<Number> exLens = parseDomain(exParts, exIdx);
            List<Number> ranLens = parseDomain(ranParts, ranIdx);
            APyNode innerNode = buildNode(innerType, exParts, ranParts, exIdx, ranIdx);
            PyListNode listNode = new PyListNode(innerNode);
            listNode.setExDomain(exLens);
            listNode.setRanDomain(ranLens);
            return listNode;
        } else if (typeStr.startsWith("set(") && typeStr.endsWith(")")) {
            String innerType = typeStr.substring(4, typeStr.length() - 1);
            List<Number> exLens = parseDomain(exParts, exIdx);
            List<Number> ranLens = parseDomain(ranParts, ranIdx);
            APyNode innerNode = buildNode(innerType, exParts, ranParts, exIdx, ranIdx);
            PySetNode setNode = new PySetNode(innerNode);
            setNode.setExDomain(exLens);
            setNode.setRanDomain(ranLens);
            return setNode;
        } else if (typeStr.startsWith("tuple(") && typeStr.endsWith(")")) {
            String innerType = typeStr.substring(6, typeStr.length() - 1);
            List<Number> exLens = parseDomain(exParts, exIdx);
            List<Number> ranLens = parseDomain(ranParts, ranIdx);
            APyNode innerNode = buildNode(innerType, exParts, ranParts, exIdx, ranIdx);
            PyTupleNode tupleNode = new PyTupleNode(innerNode);
            tupleNode.setExDomain(exLens);
            tupleNode.setRanDomain(ranLens);
            return tupleNode;
        } else if (typeStr.startsWith("dict(") && typeStr.endsWith(")")) {
            String inner = typeStr.substring(5, typeStr.length() - 1);
            int colonIdx = findTopLevelColon(inner);
            if (colonIdx < 0) {
                throw new InvalidConfigException("Invalid dict type: " + typeStr);
            }
            String keyType = inner.substring(0, colonIdx);
            String valType = inner.substring(colonIdx + 1);
            List<Number> exLens = parseDomain(exParts, exIdx);
            List<Number> ranLens = parseDomain(ranParts, ranIdx);
            APyNode keyNode = buildNode(keyType, exParts, ranParts, exIdx, ranIdx);
            APyNode valNode = buildNode(valType, exParts, ranParts, exIdx, ranIdx);
            PyDictNode dictNode = new PyDictNode(keyNode, valNode);
            dictNode.setExDomain(exLens);
            dictNode.setRanDomain(ranLens);
            return dictNode;
        } else {
            throw new InvalidConfigException("Unknown type: " + typeStr);
        }
    }

    /**
     * Finds the index of the top-level colon (at parenthesis depth 0).
     */
    private int findTopLevelColon(String s) {
        int depth = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c == '(') depth++;
            else if (c == ')') depth--;
            else if (c == ':' && depth == 0) return i;
        }
        return -1;
    }

    /**
     * Consumes the next part from the domain parts array.
     */
    private String consumePart(String[] parts, int[] idx) throws InvalidConfigException {
        if (idx[0] >= parts.length) {
            throw new InvalidConfigException("Not enough domain parts");
        }
        return parts[idx[0]++];
    }

    /**
     * Consumes and parses the next domain part into a list of Numbers.
     */
    private List<Number> parseDomain(String[] parts, int[] idx)
            throws InvalidConfigException {
        String part = consumePart(parts, idx);
        return parseDomainValue(part);
    }

    /**
     * Parses a domain value string into a list of Numbers.
     * Supports range format "lower~upper" and explicit list format "[v1,v2,...]".
     */
    private List<Number> parseDomainValue(String part) throws InvalidConfigException {
        if (part.startsWith("[") && part.endsWith("]")) {
            // Explicit list format: [1,2,3]
            String inner = part.substring(1, part.length() - 1);
            if (inner.isEmpty()) {
                return new ArrayList<>();
            }
            String[] vals = inner.split(",");
            List<Number> result = new ArrayList<>();
            for (String val : vals) {
                result.add(parseNumber(val));
            }
            return result;
        } else if (part.contains("~")) {
            // Range format: lower~upper
            String[] bounds = part.split("~");
            if (bounds.length != 2) {
                throw new InvalidConfigException("Invalid range format: " + part);
            }
            try {
                int lower = Integer.parseInt(bounds[0]);
                int upper = Integer.parseInt(bounds[1]);
                if (lower > upper) {
                    throw new InvalidConfigException(
                            "Lower bound > upper bound: " + part);
                }
                List<Number> result = new ArrayList<>();
                for (int i = lower; i <= upper; i++) {
                    result.add(i);
                }
                return result;
            } catch (NumberFormatException e) {
                throw new InvalidConfigException("Invalid range bounds: " + part);
            }
        } else {
            throw new InvalidConfigException("Invalid domain format: " + part);
        }
    }

    /**
     * Parses a string as a Number (Integer if possible, otherwise Double).
     */
    private Number parseNumber(String s) throws InvalidConfigException {
        try {
            return Integer.parseInt(s);
        } catch (NumberFormatException e1) {
            try {
                return Double.parseDouble(s);
            } catch (NumberFormatException e2) {
                throw new InvalidConfigException("Invalid number: " + s);
            }
        }
    }
}

