+        // Check for spurious characters in domain strings
+        for (String domain : exDomains) {
+            checkDomainChars(domain);
+        }
+        for (String domain : ranDomains) {
+            checkDomainChars(domain);
+        }
+
+        // Parse types and set domains on nodes
+        List<APyNode<?>> nodes = new ArrayList<>();
+        for (int i = 0; i < types.size(); i++) {
+            String[] exParts = splitDomainParts(exDomains.get(i));
+            String[] ranParts = splitDomainParts(ranDomains.get(i));
+            int[] exIdx = {0};
+            int[] ranIdx = {0};
+            APyNode<?> node = buildNode(types.get(i), exParts, ranParts, exIdx, ranIdx);
+            if (exIdx[0] != exParts.length || ranIdx[0] != ranParts.length) {
